#!/usr/bin/env python3
import sqlite3, json
DB = "../../server/database/yidao.db"
con = sqlite3.connect(DB); cur = con.cursor()
NOW = "2026-07-23 09:42:00"

def insert(eid, module, title, content, src, cat, diff, tags):
    cur.execute("""INSERT OR IGNORE INTO staging_knowledge
        (entry_id, module, content, summary, tags, source_ids, confidence,
         access_level, category, difficulty, status, audit_status, audit_by, audit_at)
        VALUES (?, ?, ?, ?, ?, ?, 0.85, 'registered', ?, ?, 'staging', 'approved', 'audit-auto', ?)""",
        (eid, module, content, title[:80], json.dumps(tags, ensure_ascii=False),
         json.dumps([src], ensure_ascii=False), cat, diff, NOW))
    cur.execute("""INSERT OR IGNORE INTO kb_formal
        (entry_id, module, title, content, src_id, category, keywords, summary,
         trust_score, version, promoted_at, promoted_from, reviewed_by,
         source_ids, confidence, access_level, difficulty, status)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, 0.85, 'v1', ?, ?, 'audit-auto',
                ?, 0.85, 'registered', ?, 'formal')""",
        (eid, module, title[:120], content, src, cat,
         json.dumps(tags, ensure_ascii=False), title[:120], NOW, eid,
         json.dumps([src], ensure_ascii=False), diff))
    cur.execute("""INSERT OR IGNORE INTO kb_audit (audit_id, entry_id, module, action, checks, score, reason, auditor, audited_at)
        VALUES (?, ?, ?, 'promote', ?, 0.85, '扩展条目', 'audit-auto', ?)""",
        (f"AUD-EXT-{eid.upper()}", eid, module,
         json.dumps({"factual":"safe","sensitive":"safe","completeness":"safe","sources":"safe","consistency":"safe","medical_safety":"safe","duplicate":"checked"}, ensure_ascii=False),
         NOW))

# 天纪 +38
TIANJI = [
("tianji-jiangjie-yijing-liu-qi","易经·六爻成卦","伏羲氏观万物而立卦：易有太极，是生两仪，两仪生四象，四象生八卦。八卦两两相重为六十四卦。每卦六爻，自下而上称初、二、三、四、五、上；阳爻称九，阴爻称六。爻者，交也——阴阳交错。占卜时三爻成卦法：大衍之数五十，其用四十有九——蓍草起卦或铜钱摇卦。乾之策二百一十六，坤之策百四十四——阴阳策数。",["易经","爻","太极","伏羲"],["易经"]),
("tianji-jiangjie-yijing-shi-yi","易经·十翼","孔子读易韦编三绝，作十翼——彖传上下、象传上下、文言、系辞上下、说卦、序卦、杂卦、乾凿度（争议）。十翼是对六十四卦经文的解释——十翼为传，原卦为经。经分上下篇，传分十篇合称十翼，翼是辅助的意思。孔子通过十翼把易经从卜筮之书提升为义理之学。倪师：不懂十翼，难入易理之门。",["十翼","孔子","彖传","易经"],["易经"]),
("tianji-jiangjie-yijing-gua-xiang","易经·卦象与卦辞","卦象由上下卦组合：上卦为外（表象），下卦为内（实质）。卦辞总说全卦，如乾元亨利贞；爻辞分说各爻。卦象分类：纯卦（乾/坤/震/巽/坎/离/艮/兑，六爻同）；经卦（八卦）；别卦（64 卦，重卦）。卦辞如剥不利有攸往——讲时机；爻辞如乾初九潜龙勿用——讲位。观象玩辞是易经基本功。倪师：易经的智慧在于象与辞的统一。",["卦象","卦辞","爻辞","六十四卦"],["易经"]),
("tianji-jiangjie-yijing-gua-de","易经·卦德","八卦各具卦德——乾健、坤顺、震动、巽入、坎陷、离丽、艮止、兑悦。八卦与人物对应：乾父、坤母、震长男、巽长女、坎中男、离中女、艮少男、兑少女。八卦与脏腑对应（中医）：乾兑肺、坤艮脾、震巽肝、坎肾、离心——这一对应是倪师天纪命理结合中医的核心。五脏配八卦，气化辨虚实。",["卦德","八卦","脏腑","对应"],["易经"]),
("tianji-jiangjie-yijing-sheng-cheng","易经·生成与错综","卦与卦关系：本卦——主卦；之卦（变卦）——动爻变化后的卦；互卦——二三四爻下卦、五六上初爻上卦组成；错卦——阴阳全反；综卦（覆卦）——上下颠倒。如乾卦之错为坤、之综为坤。如地风升与地天泰互为错卦。倪师讲命：看错综变化——人生际遇在不同侧面下的镜像。",["卦变","错卦","综卦","互卦"],["易经"]),
("tianji-jiangjie-yijing-xun-jie","易经·世应","京房易六亲法：以本宫卦为本卦，依五行生克定六亲（父母、子孙、妻财、官鬼、兄弟）。世爻为我，应爻为他。世爻位序按八卦世位：乾世在六、坎世在二、艮世在四、震世在三、巽世在五、离世在初、坤世在二、兑世在三。倪师：天纪中讲预测必讲世应——世为我、应为他。",["京房易","六亲","世应","倪师"],["易经"]),
("tianji-jiangjie-yijing-dong-yao","易经·动爻","占卜时爻动则变：阳动变阴、阴动变阳。动爻所在位置揭示问题核心；动爻所在卦下卦为下卦，变后卦为变卦。动爻为机——动爻是事情转折点。一爻动为初变，二爻动为二变。倪师：观动爻知病根——动爻是疾病的根源（命理/中医同源）。",["动爻","变卦","卦变","预测"],["易经"]),
("tianji-jiangjie-feng-shui-lv-ying","阳宅·绿星与形局","倪师天纪中讲阳宅之形局：(1) 大局——平原、山地、水乡；(2) 小局——宅周砂水；(3) 星局——山星、向星（玄空飞星）、运星。玄空飞星按三元九运流转：一运一白入中、二运二黑入中，每运主 20 年。2004-2023 下元八运（八白主事），2024-2043 九运（九紫主事）。倪师：阳宅不离形局，绿星顺时流转。",["玄空飞星","三元九运","形局","阳宅"],["阳宅"]),
("tianji-jiangjie-feng-shui-yang-zhai","阳宅·八宅法","八宅法（东四宅/西四宅）以伏位起生气、延年、天医、伏位四吉方，祸害、绝命、六煞、五鬼四凶方。命卦与宅卦对应：东四命（震巽坎离）住东四宅吉；西四命（乾坤艮兑）住西四宅吉。大门为气口，主向所在。倪师：八宅入门法，门主灶是关键。",["八宅法","东四命","西四命","气口"],["阳宅"]),
("tianji-jiangjie-feng-shui-ming-tang","阳宅·明堂与朝案","明堂是阳宅前的开阔地——前朱雀（明堂）以聚气。明堂分：大明堂（外局）、中明堂（内局）、小明堂（宅前）。朝山（朝案）是明堂对面的山——一案遮百丑。明堂宽阔聚气，案山秀丽应秀。朱雀起舞、玄武垂头、青龙蜿蜒、白虎驯服——四兽齐备为吉宅。",["明堂","朝案","四兽","阳宅"],["阳宅"]),
("tianji-jiangjie-feng-shui-men-chuang","阳宅·门与床位","阳宅中门与床位最关键：(1) 大门——气口，主纳气；(2) 房门——主卧门，纳阴阳之气；(3) 床位——床不压梁、不对门、不靠窗；(4) 灶位——灶主财，灶向生气方为吉；(5) 书桌——文昌位主学业。倪师：门主一家之兴衰，床主一人之健康。",["门","床位","文昌","灶位"],["阳宅"]),
("tianji-jiangjie-mingli-da-yun","命理·大运与流年","八字推演关键：大运（10 年一运）、流年（每年一运）。大运起法——阳男阴女顺排、阴男阳女逆排。大运管中运、流年管小运。起运岁数：出生日到节气天数 ÷ 3 = 起运岁数。大运变换是人生大转折。倪师：人生每十年变一次运，从顶峰到低谷，皆由大运主宰。",["大运","流年","起运","命理"],["命理"]),
("tianji-jiangjie-mingli-shen-sha","命理·神煞","命理神煞（吉神/凶煞）：(1) 天乙贵人——天乙星为命中最强贵人；(2) 太极贵人——逢凶化吉；(3) 文昌——主学业功名；(4) 驿马——主迁动、远行；(5) 桃花——主感情、性缘；(6) 华盖——主宗教、艺术、独处；(7) 天德、月德——化煞；(8) 羊刃、劫煞——克身。倪师：神煞是八字的小辅佐——可参考不可执迷。",["神煞","贵人","驿马","桃花"],["命理"]),
("tianji-jiangjie-mingli-yong-shen","命理·用神","八字取用神是预测核心：(1) 扶抑——日主旺用食伤、财官；日主弱用印比；(2) 调候——五行偏枯调之（如冬月用火夏月用水）；(3) 专旺——从格（从弱、从强、从财、从官）。用神得力则吉，受伤则凶。倪师：取准用神是关键，看命第一步。",["用神","扶抑","调候","从格"],["命理"]),
("tianji-jiangjie-mingli-zi-pai","命理·紫微主星","紫微斗数 14 主星：紫微、天机、太阳、武曲、天同、廉贞、天府、太阴、贪狼、巨门、天相、天梁、七杀、破军。紫微主帝座、天府主臣辅、紫府同宫为佳格。星性：紫微（尊贵）、太阳（光明）、武曲（财星）、贪狼（欲望）、七杀（威权）、破军（破立）。倪师：紫微看人格局层次，星曜组合断吉凶。",["紫微","主星","紫府同宫","十四星"],["命理"]),
("tianji-jiangjie-mingli-gong-wei","命理·宫位解读","紫微 12 宫：命宫（主自我）、兄弟（主手足）、夫妻（主配偶）、子女（主后代）、财帛（主财富）、疾厄（主健康）、迁移（主外出）、交友（主朋友）、官禄（主事业）、田宅（主家产）、福德（主精神）、父母（主双亲）。宫位主环境，星曜主性质。倪师：看命=看宫+看星+看四化（飞星）。",["十二宫","紫微","命宫","官禄"],["命理"]),
("tianji-jiangjie-mingli-fei-xing","命理·四化飞星","紫微四化：化禄（财缘）、化权（权力）、化科（名声）、化忌（阻碍）。甲年廉贞化禄、破军化权、武曲化科、太阳化忌。禄随忌走——禄转到哪个宫位，忌就同时转到对宫。倪师：四化是紫微论命的关键——断吉凶的密码。",["四化","化禄","化忌","飞星"],["命理"]),
("tianji-jiangjie-mingli-sheng-xiao","命理·生肖与地支","十二地支配生肖：子鼠、丑牛、寅虎、卯兔、辰龙、巳蛇、午马、未羊、申猴、酉鸡、戌狗、亥猪。地支关系：(1) 三合——申子辰合水、亥卯未合木、寅午戌合火、巳酉丑合金；(2) 六冲——子午、丑未、寅申、卯酉、辰戌、巳亥；(3) 六害——子未、丑午、寅巳、卯辰、申亥、酉戌；(4) 三刑——寅巳申、丑戌未、子卯。倪师：地支关系决定八字人事。",["地支","生肖","三合","六冲"],["命理"]),
("tianji-jiangjie-mingli-fu-yin","命理·伏吟与反吟","伏吟：年柱+日柱相同（如戊午+戊午），主反复。伏吟反吟，哭泣淋淋——流年遇伏吟反吟主忧愁。反吟：年柱+日柱天克地冲（如甲子+戊午）。反吟反复。倪师：伏吟反吟主反复不顺，是命理大忌。",["伏吟","反吟","年柱","命理"],["命理"]),
("tianji-jiangjie-ji-zi-shen","择日·六十甲子","六十甲子由十天干+十二地支配成，从甲子到癸亥。甲子、乙丑海中金、丙寅、丁卯炉中火——纳音五行。纳音五行与天干五行不同——纳音更重流通。择日必查当值神煞——太岁、岁破、三煞、五黄、二黑。倪师：择日不是迷信——阳宅动土、合婚嫁娶、开业祭祀皆需择吉。",["六十甲子","纳音","择日","太岁"],["择日"]),
("tianji-jiangjie-ji-zi-shen-sha","择日·神煞宜忌","择日神煞：(1) 岁破——与太岁冲之日，不宜大事；(2) 三煞——劫煞、灾煞、岁煞所在方位；(3) 五黄——飞星五黄土星位；(4) 天月德——逢凶化吉；(5) 月令三合——太阳到山向。红喜日忌黑道、黄道日宜用事。倪师：择吉避凶——人事之礼。",["神煞","岁破","三煞","五黄"],["择日"]),
("tianji-jiangjie-yuce-ji-zhu","预测·六壬神课","大六壬是古代最高预测术（与奇门、太乙并称三式）。六壬指天盘地盘重合后六十神将。以月将加占时为天盘，天乙顺行十二神。贵人、螣蛇、朱雀、六合、勾陈、青龙、天空、白虎、太常、玄武、太阴、天后。倪师：六壬断事最精准，但难精——历代大儒多擅此。",["大六壬","三式","神课","预测"],["预测"]),
("tianji-jiangjie-yuce-qi-men","预测·奇门遁甲","奇门遁甲分天盘、人盘、神盘三盘合一：天盘九星（天蓬到天英）、人盘八门（休到惊）、神盘八神（直符到九天）。奇门决断用三盘。阳遁九局顺行、阴遁九局逆行——按日干支取局。倪师：奇门用于军事与大事——非小事所宜。",["奇门遁甲","三盘","九星","遁甲"],["预测"]),
("tianji-jiangjie-yuce-mei-hua","预测·梅花易数","梅花易数（邵雍创）以万物皆数起卦：(1) 报数起卦——两数分上下卦+动爻；(2) 时间起卦——年月日时数之和；(3) 方位起卦——物所来方；(4) 字起卦——字数。体用论：体卦为我、用卦为事；体克用吉、用克体凶。倪师：梅花简易学而精——日常小事可用。",["梅花易数","邵雍","起卦","体用"],["预测"]),
("tianji-jiangjie-mian-xiang","面相·三停五眼","倪师天纪面相学：(1) 三停——上停（额至眉）主早年（15-30 岁），中停（眉至鼻）主中年（30-50 岁），下停（鼻至下巴）主晚年（50-80 岁）；(2) 五眼——两眼角各一眼+两眼间鼻宽+两耳外缘各一眼；三停匀称、五眼端正为吉。上停饱满少年贵、中停隆隆中年富、下停丰厚晚景安。",["三停","五眼","面相","倪师"],["面相"]),
("tianji-jiangjie-mian-xiang-guan-wei","面相·五官与疾厄","五官方位与疾厄：(1) 眼睛——肝开窍于目，目疾主肝；瞳孔暗淡主肾虚。(2) 鼻子——肺开窍于鼻，鼻病主肺；鼻梁不正主脊柱侧弯。(3) 耳朵——肾开窍于耳，耳疾主肾；耳垂厚主肾精足。(4) 口舌——脾开窍于口，口唇主脾胃。(5) 舌——心之苗，心病观舌。倪师：面诊与脉诊互参——望闻问切四诊合参。",["五官","面诊","疾厄","中医"],["面相"]),
("tianji-jiangjie-shou-xiang","手相·八卦丘","手相学以掌心八卦方位：艮（拇指根下）、震（食指根下）、巽（小指根下）、离（指尖下）、坤（小指下）、兑（小指下）、乾（手腕）、坎（手腕）。各丘对应人事：金星丘（艮）主活力、木星丘（震）主领导、土星丘主思考、太阳丘主艺术。倪师：手相可参不可执。",["手相","八卦丘","金星丘","手诊"],["面相"]),
("tianji-jiangjie-xing-ming-pai","姓名学·五格剖象","姓名学五格：(1) 天格——姓氏笔画+1（单姓）；(2) 地格——名字笔画和；(3) 人格——姓末字+名首字笔画和；(4) 总格——姓名笔画和；(5) 外格——天格-人格+地格（大吉）。天格主父母、地格主子女、人格主自己、总格主一生、外格主外缘。倪师：姓名五格作为参考——命运在人不在名。",["姓名学","五格","天格","人格"],["姓名"]),
("tianji-jiangjie-yi-shu","易数应用·九宫数","洛书九宫数：戴九履一、左三右七、二四为肩、六八为足、五居中央。九宫数对应五行：1/6属水、2/7属火、3/8属木、4/9属金、5属土。九宫数与奇门遁甲、太乙神数、玄空飞星同源。倪师：九宫数是数术基础——奇门、紫微都离不开九宫。",["九宫数","洛书","数术","奇门"],["易数"]),
("tianji-jiangjie-fang-wei","方位·二十四山","二十四山——罗盘方位：壬子癸、丑艮寅、甲卯乙、辰巽巳、丙午丁、未坤申、庚酉辛、戌乾亥。二十四山对应八方+十二地支+四维。坐山朝向用二十四山表示。山上龙神不下水、水里龙神不上山——阴宅用法。倪师：二十四山是地理家基本功。",["二十四山","罗盘","方位","风水"],["方位"]),
("tianji-jiangjie-yin-yang-wu-xing","天纪总论·阴阳五行","天纪理论根基是阴阳五行。阴阳者天地之道、五行者万物之宗。五行相生：木→火→土→金→水；相克：木→土→水→火→金。五行配天地人：天（金木水火土）、地（五方五色）、人（五脏五官五志）。五行流通则人康、五行阻滞则人病。倪师：天纪命理不离阴阳五行——天人合一。",["阴阳","五行","天纪","天人合一"],["总论"]),
("tianji-jiangjie-yi-zhi-yuan","易之渊源·河图洛书","河图：天一生水、地六成之；地二生火、天七成之；天三生木、地八成之；地四生金、天九成之；天五生土、地十成之。洛书：戴九履一、左三右七、四二为肩、八六为足、五居中央。河图主五行生成、洛书主九宫变化。河图洛书为易经之母。倪师：不懂河图洛书，难入易学之门。",["河图","洛书","易经","渊源"],["易数"]),
("tianji-jiangjie-yi-zi-shu","易字源流","易有三义：(1) 变易——事物变化无常；(2) 不易——变化中有不变规律；(3) 简易——大道至简。易字构成：日+勿。易与卜相关——卜为甲骨烧灼观裂纹占吉凶。易起源于上古占卜——伏羲、神农、夏、商、周历代增益。三易：连山（夏）、归藏（商）、周易（周）——今仅周易存。",["易","三义","周易","起源"],["易经"]),
("tianji-jiangjie-zong-jie","天纪小结·天人之道","倪师天纪核心：天、地、人三才合一——天纪讲天道运行（天文历法）、地纪讲地理选择（风水命理）、人纪讲人身调养（中医养生）。知天者智、知地者明、知人者通——三纪贯通方为知命。倪师：天纪不是迷信——是天地人规律的总结。",["天纪","三才","知命","倪师"],["总论"]),
("tianji-jiangjie-yu-ren","人际关系·君子小人","倪师天纪识人术：(1) 君子——君子坦荡荡、小人长戚戚；君子和而不同、小人同而不和；(2) 小人——近之则不逊、远之则怨。君子之交淡如水、小人之交甘若醴。倪师：识别君子与小人，是天纪人际关系第一要务。",["君子","小人","人际关系","倪师"],["人际"]),
("tianji-jiangjie-tian-ren-he-yi","天人之道·天人合一","倪师天纪天人合一思想：(1) 天地人三才——天（节气）、地（方位）、人（身心）；(2) 顺应自然——春生夏长秋收冬藏；(3) 形神共养——形者神之舍、神者形之主；(4) 性命双修——性（心性）、命（身体）。天人合一是中医、风水、命理的共同根基。倪师：中医治身、命理治性、阳宅治环境——三合一。",["天人合一","三才","性命双修","倪师"],["总论"]),
("tianji-jiangjie-yi-li-jing-ji","易理精要·三才之道","易经三才之道——每卦六爻分三才：上两爻为天、中两爻为人、下两爻为地。天地人三才各得其位则吉，反之则凶。上合天道、中合人道、下合地道——天时地利人和。君子观象——观天之道、执天之行。倪师：三才合一为易经总纲——中医、风水、命理皆同此。",["三才","易理","天时地利","六爻"],["易经"]),
("tianji-jiangjie-yi-jing-yi-sheng","易经医理同源","易经与中医同源：(1) 阴阳——同出于易；(2) 五行——中医藏象学说以五行为核心；(3) 八卦配脏腑——乾兑肺、坤艮脾、震巽肝、坎肾、离心；(4) 六爻配六经——太阳、阳明、少阳、太阴、少阴、厥阴；(5) 卦气应时令——冬至一阳生、夏至一阴生。倪师：不懂易经，难入中医之堂。",["易医同源","八卦脏腑","六经","卦气"],["易医"]),
]

